import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

function Register() {
  const navigate = useNavigate();
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    setError('');
    if (password !== confirmPassword) { setError('Passwords do not match!'); return; }
    if (password.length < 6) { setError('Password must be at least 6 characters.'); return; }
    setShowConfirm(true);
  };

  const doRegister = async () => {
    setShowConfirm(false);
    setLoading(true);
    setError('');
    try {
      const response = await axios.post('http://localhost:5000/api/auth/signup', {
        name: name,
        email: email,
        password: password,
      });
      const data = response.data;
      localStorage.setItem('token', data.token);
      localStorage.setItem('user', JSON.stringify(data.user));
      navigate('/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0, left: 0, right: 0, bottom: 0,
      background: 'linear-gradient(135deg, #fdf6f3, #f9ede8, #f5e0d8)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'DM Sans, sans-serif',
      overflow: 'hidden',
    }}>

      {/* Confirm Modal */}
      {showConfirm && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(45,31,31,0.6)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
          <div style={{ background: 'white', borderRadius: '20px', padding: '2rem', maxWidth: '380px', width: '90%', textAlign: 'center', boxShadow: '0 20px 60px rgba(0,0,0,0.2)' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🚀</div>
            <h3 style={{ color: '#2d1f1f', marginBottom: '0.5rem', fontSize: '1.2rem' }}>Create Your Account?</h3>
            <p style={{ color: '#a08880', fontSize: '0.85rem', marginBottom: '1.5rem' }}>Welcome {name}! Joining EventHub with {email}</p>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => setShowConfirm(false)} style={{ flex: 1, padding: '11px', background: '#f5e8e3', color: '#a08880', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: '600' }}>Go Back</button>
              <button onClick={doRegister} style={{ flex: 2, padding: '11px', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: '700' }}>Yes, Create Account 🌸</button>
            </div>
          </div>
        </div>
      )}

      {/* Main Card */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', maxWidth: '820px', width: '95%', borderRadius: '24px', overflow: 'hidden', boxShadow: '0 25px 70px rgba(201,169,154,0.35)', border: '1px solid #f0ddd7' }}>

        {/* LEFT — form */}
        <div style={{ background: '#fffaf8', padding: '2.5rem 2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>

          {/* Logo */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '1.5rem' }}>
            <div style={{ width: '32px', height: '32px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>🌸</div>
            <span style={{ fontWeight: '700', fontSize: '1.1rem', color: '#2d1f1f' }}>Event<span style={{ color: '#c9a99a' }}>Hub</span></span>
          </div>

          <h1 style={{ color: '#2d1f1f', fontSize: '1.6rem', fontWeight: '700', marginBottom: '0.3rem' }}>Create Account</h1>
          <p style={{ color: '#a08880', fontSize: '0.83rem', marginBottom: '1.2rem' }}>Join our lovely community 🌷</p>

          {error && (
            <div style={{ background: '#fdeee9', border: '1px solid #f0c4b8', color: '#a05040', padding: '10px 13px', borderRadius: '10px', marginBottom: '1rem', fontSize: '0.82rem' }}>
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            {/* Name */}
            <div style={{ marginBottom: '0.85rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '5px' }}>FULL NAME</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)' }}>👤</span>
                <input type="text" value={name} onChange={e => setName(e.target.value)} required placeholder="Your name"
                  style={{ width: '100%', padding: '10px 12px 10px 38px', border: '1.5px solid #f0ddd7', borderRadius: '10px', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#2d1f1f' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            {/* Email */}
            <div style={{ marginBottom: '0.85rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '5px' }}>EMAIL ADDRESS</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)' }}>✉️</span>
                <input type="email" value={email} onChange={e => setEmail(e.target.value)} required placeholder="you@example.com"
                  style={{ width: '100%', padding: '10px 12px 10px 38px', border: '1.5px solid #f0ddd7', borderRadius: '10px', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#2d1f1f' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            {/* Password */}
            <div style={{ marginBottom: '0.85rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '5px' }}>PASSWORD</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)' }}>🔑</span>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} required placeholder="Min 6 characters"
                  style={{ width: '100%', padding: '10px 12px 10px 38px', border: '1.5px solid #f0ddd7', borderRadius: '10px', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#2d1f1f' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            {/* Confirm Password */}
            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '5px' }}>CONFIRM PASSWORD</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)' }}>✅</span>
                <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} required placeholder="Repeat password"
                  style={{ width: '100%', padding: '10px 12px 10px 38px', border: '1.5px solid #f0ddd7', borderRadius: '10px', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#2d1f1f' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            <button type="submit" disabled={loading}
              style={{ width: '100%', padding: '13px', background: loading ? '#ccc' : 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '10px', fontWeight: '700', fontSize: '0.92rem', cursor: loading ? 'not-allowed' : 'pointer', boxShadow: '0 5px 18px rgba(201,169,154,0.4)' }}>
              {loading ? '✨ Creating...' : '🌸 Create Account'}
            </button>
          </form>

          <p style={{ marginTop: '1rem', textAlign: 'center', color: '#a08880', fontSize: '0.82rem' }}>
            Already have an account?{' '}
            <Link to="/login" style={{ color: '#c9a99a', fontWeight: '700' }}>Sign In →</Link>
          </p>
        </div>

        {/* RIGHT — promo */}
        <div style={{ background: 'linear-gradient(150deg, #c9a99a, #b8887a, #a0706a)', padding: '2.5rem 2rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
          <div style={{ fontSize: '2.2rem', marginBottom: '1rem' }}>🚀</div>
          <h2 style={{ color: 'white', fontSize: '1.8rem', fontWeight: '700', marginBottom: '0.8rem', lineHeight: '1.3' }}>Join EventHub!</h2>
          <p style={{ color: 'rgba(255,255,255,0.8)', fontSize: '0.85rem', lineHeight: '1.7', marginBottom: '1.5rem' }}>Explore and book amazing events near you. Free forever.</p>
          {[
            { icon: '🆓', text: 'Free to join always' },
            { icon: '🔔', text: 'Event notifications' },
            { icon: '🎟️', text: 'Instant booking' },
            { icon: '💝', text: 'Exclusive deals' },
          ].map((item, i) => (
            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '10px' }}>
              <div style={{ width: '32px', height: '32px', background: 'rgba(255,255,255,0.2)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.85rem' }}>{item.icon}</div>
              <span style={{ color: 'rgba(255,255,255,0.9)', fontSize: '0.82rem' }}>{item.text}</span>
            </div>
          ))}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginTop: '1.5rem' }}>
            {[{ num: '10K+', label: 'Members' }, { num: '500+', label: 'Events' }, { num: '50K+', label: 'Tickets' }, { num: '4.9★', label: 'Rating' }].map((s, i) => (
              <div key={i} style={{ background: 'rgba(255,255,255,0.15)', borderRadius: '10px', padding: '0.8rem', textAlign: 'center' }}>
                <p style={{ color: 'white', fontWeight: '800', fontSize: '1rem', margin: 0 }}>{s.num}</p>
                <p style={{ color: 'rgba(255,255,255,0.65)', fontSize: '0.7rem', margin: 0 }}>{s.label}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
